        ChartLabelHelper.ApplyTo(categoryAxis, LabelStrategy, Categories.Count, LabelRotate);
        var valueAxis = new EChartAxis { Type = "value" };

        var seriesList = Series.Select(s => new EChartSeries
        {
            Name = s.Name,
            Type = "bar",
            Data = s.Values,
            Stack = Stacked ? "total" : null
        }).ToList();

        // When stacked, the theme's rounded corners on every segment make
        // the stack look like floating pills (each segment rounds its own
        // 4 corners, so adjacent segments meet at the arc). We flatten
        // the inner segments and round only the outermost end of the stack:
        //
        //   Vertical stacked   → last series (top) rounds top corners
        //   Horizontal stacked → last series (right) rounds right corners
        //
        // Radius is derived from --radius (fallback 6 px if unavailable
        // from the CSS side since we're in C#). Consumers who want a
        // different value can override via OptionOverride on the series.
        if (Stacked && seriesList.Count > 0)
        {
            const int r = 6;
            int[] outerCorners = Horizontal
                ? new[] { 0, r, r, 0 }   // round right side
                : new[] { r, r, 0, 0 };  // round top side
            int[] flat = { 0, 0, 0, 0 };

            // Use the array form everywhere — ECharts merges theme + series
            // itemStyle and a scalar `borderRadius: 0` doesn't reliably replace
            // the theme's array default; an all-zero array always wins.
            for (int i = 0; i < seriesList.Count; i++)
