                seriesList[i].ItemStyle = new EChartItemStyle
                {
                    BorderRadiusCorners = isOuter ? outerCorners : flat
                };
            }
        }
        else if (Horizontal)
        {
            // Non-stacked horizontal: theme default `[r, r, 0, 0]` rounds the
            // TOP edge (rectangle corners), which looks wrong for a horizontal
            // bar. Override so every bar's right end is rounded instead.
            const int r = 6;
            foreach (var s in seriesList)
                s.ItemStyle = new EChartItemStyle { BorderRadiusCorners = new[] { 0, r, r, 0 } };
        }

        if (ShowDataLabels)
            foreach (var s in seriesList)
                s.Label = new EChartLabel { Show = true, Position = LabelPosition, Formatter = LabelFormat };

        if (seriesList.Count > 0)
        {
            if (MarkLine is not null) seriesList[0].MarkLine = MarkLine;
            if (MarkPoint is not null) seriesList[0].MarkPoint = MarkPoint;
            if (MarkArea is not null) seriesList[0].MarkArea = MarkArea;
        }

        _option = new EChartOption
        {
            XAxis = new List<EChartAxis> { Horizontal ? valueAxis : categoryAxis },
            YAxis = new List<EChartAxis> { Horizontal ? categoryAxis : valueAxis },
            Series = seriesList,
            Grid = new EChartGrid
            {
                Left = "3%", Right = "4%",
                Top = ShowLegend ? "14%" : "5%",
                Bottom = DataZoom ? "15%" : "3%",
                ContainLabel = true
            },
            Color = ColorPalette ?? Colors
        };

